1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Edge cases / simplest
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result.results[0]).toEqual({ premium: 5 });
12	  });
13	
14	  // Per spec ❓: each item in a quote is treated as a first insurance,
15	  // so a 10% first-insurance surcharge applies on the policy base premium
16	  // for every quote.
17	
18	  // Base premiums for main items (base + 10% first-ins + 5 G fee)
19	  it("single sword → premium 115 G (100 base + 10 first-ins + 5 fee)", () => {
20	    const result = runScenario({
21	      customer: { yearsWithMHPCO: 0 },
22	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
23	    });
24	    expect(result.results[0]).toEqual({ premium: 115 });
25	  });
26	  it("single amulet → premium 71 G (60 base + 6 first-ins + 5 fee)", () => {
27	    const result = runScenario({
28	      customer: { yearsWithMHPCO: 0 },
29	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
30	    });
31	    expect(result.results[0]).toEqual({ premium: 71 });
32	  });
33	  it("single staff → premium 93 G (80 base + 8 first-ins + 5 fee)", () => {
34	    const result = runScenario({
35	      customer: { yearsWithMHPCO: 0 },
36	      steps: [{ op: "quote", items: [{ type: "staff" }] }],
37	    });
38	    expect(result.results[0]).toEqual({ premium: 93 });
39	  });
40	  it("single potion → premium 49 G (40 base + 4 first-ins + 5 fee)", () => {
41	    const result = runScenario({
42	      customer: { yearsWithMHPCO: 0 },
43	      steps: [{ op: "quote", items: [{ type: "potion" }] }],
44	    });
45	    expect(result.results[0]).toEqual({ premium: 49 });
46	  });
47	
48	  // Component pricing
49	  it("2 runes → 50 G base + 5 first-ins + 5 fee = 60 G", () => {
50	    const result = runScenario({
51	      customer: { yearsWithMHPCO: 0 },
52	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
53	    });
54	    expect(result.results[0]).toEqual({ premium: 60 });
55	  });
56	  it("3 runes → 60 G base premium block + 6 first-ins + 5 fee = 71 G", () => {
57	    const result = runScenario({
58	      customer: { yearsWithMHPCO: 0 },
59	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
60	    });
61	    expect(result.results[0]).toEqual({ premium: 71 });
62	  });
63	  it("4 runes → 100 G base no block + 10 first-ins + 5 fee = 115 G", () => {
64	    const result = runScenario({
65	      customer: { yearsWithMHPCO: 0 },
66	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }],
67	    });
68	    expect(result.results[0]).toEqual({ premium: 115 });
69	  });
70	  it("7 runes → 175 G base + 17.5 first-ins + 5 fee = 197.5 → rounded up to 198 G", () => {
71	    const items = Array.from({ length: 7 }, () => ({ type: "rune" }));
72	    const result = runScenario({
73	      customer: { yearsWithMHPCO: 0 },
74	      steps: [{ op: "quote", items }],
75	    });
76	    expect(result.results[0]).toEqual({ premium: 198 });
77	  });
78	
79	  // "Alike" components clarification
80	  it("2 runes + 1 moonstone → 75 G base + 7.5 first-ins + 5 fee = 87.5 → 88 G", () => {
81	    const result = runScenario({
82	      customer: { yearsWithMHPCO: 0 },
83	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] }],
84	    });
85	    expect(result.results[0]).toEqual({ premium: 88 });
86	  });
87	  it("3 runes + 3 moonstones → 120 G base (two blocks) + 12 first-ins + 5 fee = 137 G", () => {
88	    const result = runScenario({
89	      customer: { yearsWithMHPCO: 0 },
90	      steps: [{ op: "quote", items: [
91	        { type: "rune" }, { type: "rune" }, { type: "rune" },
92	        { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
93	      ] }],
94	    });
95	    expect(result.results[0]).toEqual({ premium: 137 });
96	  });
97	
98	  // Item-specific modifiers (cursed/enchantment apply per item; first-ins still applies on policy base)
99	  it("cursed sword adds 50% on item base → 100 + 50 curse + 10 first-ins + 5 fee = 165 G", () => {
100	    const result = runScenario({
101	      customer: { yearsWithMHPCO: 0 },
102	      steps: [{ op: "quote", items: [{ type: "sword", cursed: true }] }],
103	    });
104	    expect(result.results[0]).toEqual({ premium: 165 });
105	  });
106	  it("highly enchanted sword (ench 5) → 100 + 30 ench + 10 first-ins + 5 fee = 145 G", () => {
107	    const result = runScenario({
108	      customer: { yearsWithMHPCO: 0 },
109	      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 5 }] }],
110	    });
111	    expect(result.results[0]).toEqual({ premium: 145 });
112	  });
113	  it("sword with enchantment 4 → no high-ench surcharge: 100 + 10 first-ins + 5 fee = 115 G", () => {
114	    const result = runScenario({
115	      customer: { yearsWithMHPCO: 0 },
116	      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 4 }] }],
117	    });
118	    expect(result.results[0]).toEqual({ premium: 115 });
119	  });
120	  it("cursed sword with enchantment 5 → 100 + 50 + 30 + 10 first-ins + 5 fee = 195 G", () => {
121	    const result = runScenario({
122	      customer: { yearsWithMHPCO: 0 },
123	      steps: [{ op: "quote", items: [{ type: "sword", cursed: true, enchantment: 5 }] }],
124	    });
125	    expect(result.results[0]).toEqual({ premium: 195 });
126	  });
127	
128	  // Policy-wide modifiers
129	  it("first insurance adds 10% per item → sword 100 + 10 = 110, 115 with fee (per spec ❓: each item in a quote is a first insurance)", () => {
130	    const result = runScenario({
131	      customer: { yearsWithMHPCO: 0 },
132	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
133	    });
134	    expect(result.results[0]).toEqual({ premium: 115 });
135	  });
136	  it("loyalty discount: customer with exactly 2 years → 20% off policy (sword: 100 - 20 + 10 + 5 = 95)", () => {
137	    const result = runScenario({
138	      customer: { yearsWithMHPCO: 2 },
139	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
140	    });
141	    expect(result.results[0]).toEqual({ premium: 95 });
142	  });
143	  it.todo("follow-up contract: second quote in scenario gets 15% discount");
144	
145	  // Modifier scope on multi-item policies
146	  it.todo("policy with cursed sword + plain amulet → cursed surcharge only on sword's base premium (160 + 50 = 210 before fee and other modifiers)");
147	
148	  // Rounding
149	  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");
150	
151	  // Integration examples
152	  it.todo("newcomer with cursed sword (steel, ench 3) → 165 G");
153	  it.todo("long-standing customer's second contract: cursed sword (steel, ench 7), 3 years → 160 G");
154	
155	  // Claim: standard reimbursement
156	  it.todo("regular sword damage 500 G → payout 400 G (deductible 100)");
157	  it.todo("rune damage 200 G → payout 100 G (no special clauses, deductible)");
158	
159	  // Enchantment threshold vs dragon material
160	  it.todo("dragon-material sword, enchantment 8, damage 1000 G → payout 400 G (50% rule + deductible)");
161	  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
162	  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (full reimbursement minus deductible)");
163	  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
164	
165	  // Deductible per damage event
166	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible per item)");
167	
168	  // Multiple items of same type
169	  it.todo("policy covers two swords → insurance sum 2000, cap 4000");
170	  it.todo("two sword damages with two swords insured → each treated as separate damage with own deductible");
171	  it.todo("damages contain more entries of a type than insured (2 sword damages, 1 sword) → claim rejected (error)");
172	
173	  // Cap exhaustion
174	  it.todo("sword + amulet policy → insurance sum 1600, cap 3200");
175	  it.todo("cursed sword (premium with modifiers 165) → cap 2000 (based on unmodified insurance value)");
176	  it.todo("sword + 3 runes block → insurance sum 1750 (block discount affects premium only)");
177	  it.todo("sword cap 2000, two claims of 1500 each → first payout 1400 (cap 600 remaining), second payout 600 (cap 0)");
178	
179	  // Payout rounding
180	  it.todo("payout yielding 350.5 G → final payout 350 G (rounded down)");
181	
182	  // Edge cases / errors
183	  it.todo("quote with unknown item type → CLI exits non-zero, error to stderr");
184	  it.todo("claim references item not in policy → CLI exits non-zero, error to stderr");
185	  it.todo("claim contains damage with negative amount → CLI exits non-zero, error to stderr");
186	});
