1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	export interface Damage {
18	  itemType: string;
19	  amount: number;
20	}
21	
22	export interface Incident {
23	  cause: string;
24	  damages: Damage[];
25	}
26	
27	export interface ClaimStep {
28	  op: "claim";
29	  policy: number;
30	  incident: Incident;
31	}
32	
33	export type Step = QuoteStep | ClaimStep;
34	
35	export interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	export interface QuoteResult {
41	  premium: number;
42	}
43	
44	export interface ClaimResult {
45	  payout: number;
46	  remainingCap: number;
47	}
48	
49	export type StepResult = QuoteResult | ClaimResult;
50	
51	export interface ScenarioResult {
52	  results: StepResult[];
53	}
54	
55	const PROCESSING_FEE = 5;
56	
57	const BASE_PREMIUM: Record<string, number> = {
58	  sword: 100,
59	  amulet: 60,
60	  staff: 80,
61	  potion: 40,
62	  rune: 25,
63	  moonstone: 25,
64	};
65	
66	const CURSED_SURCHARGE_RATE = 0.5;
67	const HIGH_ENCHANTMENT_THRESHOLD = 5;
68	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
69	const FIRST_INSURANCE_RATE = 0.1;
70	const LOYALTY_THRESHOLD_YEARS = 2;
71	const LOYALTY_DISCOUNT_RATE = 0.2;
72	
73	const isCursed = (item: Item): boolean => item.cursed === true;
74	const isHighlyEnchanted = (item: Item): boolean =>
75	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
76	
77	const surchargeRate = (item: Item): number =>
78	  (isCursed(item) ? CURSED_SURCHARGE_RATE : 0) +
79	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
80	
81	const itemBaseValue = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;
82	
83	const itemSurcharge = (item: Item): number =>
84	  itemBaseValue(item) * surchargeRate(item);
85	
86	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
87	const BLOCK_SIZE = 3;
88	const BLOCK_PREMIUM = 60;
89	
90	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
91	
92	const sumBy = <T>(values: T[], measure: (value: T) => number): number =>
93	  values.reduce((sum, value) => sum + measure(value), 0);
94	
95	const groupByType = (items: Item[]): Item[][] => {
96	  const byType = new Map<string, Item[]>();
97	  for (const item of items) {
98	    const group = byType.get(item.type) ?? [];
99	    group.push(item);
100	    byType.set(item.type, group);
101	  }
102	  return [...byType.values()];
103	};
104	
105	const groupPremium = (group: Item[]): number =>
106	  group.length === BLOCK_SIZE ? BLOCK_PREMIUM : sumBy(group, itemBaseValue);
107	
108	const componentsPremium = (components: Item[]): number =>
109	  sumBy(groupByType(components), groupPremium);
110	
111	const policyBasePremium = (items: Item[]): number =>
112	  componentsPremium(items.filter(isComponent)) +
113	  sumBy(items.filter((item) => !isComponent(item)), itemBaseValue);
114	
115	const totalSurcharges = (items: Item[]): number => sumBy(items, itemSurcharge);
116	
117	const loyaltyDiscount = (customer: Customer, base: number): number =>
118	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_DISCOUNT_RATE : 0;
119	
120	const quotePremium = (customer: Customer, items: Item[]): number => {
121	  const base = policyBasePremium(items);
122	  const surcharges = totalSurcharges(items);
123	  const firstInsurance = base * FIRST_INSURANCE_RATE;
124	  const loyalty = loyaltyDiscount(customer, base);
125	  return Math.ceil(base + surcharges + firstInsurance - loyalty + PROCESSING_FEE);
126	};
127	
128	export const runScenario = (scenario: Scenario): ScenarioResult => {
129	  const results = scenario.steps.map((step): StepResult => {
130	    if (step.op === "quote") {
131	      return { premium: quotePremium(scenario.customer, step.items) };
132	    }
133	    return { payout: 0, remainingCap: 0 };
134	  });
135	  return { results };
136	};
